-- ФИНАНСОВЫЕ ДОГОВОРЫ
INSERT INTO contract_templates (name, category, description, template_content, variables) VALUES 
('Договор банковского вклада', 'financial', 'Договор банковского вклада физического лица', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР БАНКОВСКОГО ВКЛАДА № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{bank_name}}, именуемый в дальнейшем "Банк", с одной стороны, и {{depositor_name}}, именуемый(-ая) в дальнейшем "Вкладчик", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Вкладчик вносит в Банк денежные средства в размере {{deposit_amount}} рублей под {{interest_rate}}% годовых.</p><p style="text-align: justify;">1.2. Срок вклада: {{deposit_term}}.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Банк:</strong><br/>{{bank_name}}<br/>Лицензия: {{bank_license}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{bank_signature}}/</td><td width="50%" style="text-align: center;"><strong>Вкладчик:</strong><br/>{{depositor_name}}<br/>Паспорт: {{depositor_passport}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{depositor_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'bank_name', 'Наименование банка', 'depositor_name', 'ФИО вкладчика', 'deposit_amount', 'Сумма вклада', 'interest_rate', 'Процентная ставка', 'deposit_term', 'Срок вклада', 'bank_license', 'Лицензия банка', 'depositor_passport', 'Паспорт вкладчика', 'bank_signature', 'Подпись банка', 'depositor_signature', 'Подпись вкладчика')),

('Договор лизинга', 'financial', 'Договор финансовой аренды (лизинга)', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР ФИНАНСОВОЙ АРЕНДЫ (ЛИЗИНГА) № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{lessor_name}}, именуемый в дальнейшем "Лизингодатель", с одной стороны, и {{lessee_name}}, именуемый в дальнейшем "Лизингополучатель", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Лизингодатель обязуется приобрести в собственность указанное Лизингополучателем имущество {{leased_property}} и предоставить его Лизингополучателю за плату во временное владение и пользование.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ЛИЗИНГОВЫЕ ПЛАТЕЖИ</div><p style="text-align: justify;">2.1. Размер лизингового платежа составляет {{lease_payment}} рублей в месяц.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Лизингодатель:</strong><br/>{{lessor_name}}<br/>Адрес: {{lessor_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{lessor_signature}}/</td><td width="50%" style="text-align: center;"><strong>Лизингополучатель:</strong><br/>{{lessee_name}}<br/>Адрес: {{lessee_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{lessee_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'lessor_name', 'Наименование лизингодателя', 'lessee_name', 'Наименование лизингополучателя', 'leased_property', 'Описание лизингового имущества', 'lease_payment', 'Размер лизингового платежа', 'lessor_address', 'Адрес лизингодателя', 'lessee_address', 'Адрес лизингополучателя', 'lessor_signature', 'Подпись лизингодателя', 'lessee_signature', 'Подпись лизингополучателя')),

-- КОММЕРЧЕСКИЕ ДОГОВОРЫ
('Договор поручения', 'commercial', 'Договор поручения на совершение юридических действий', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР ПОРУЧЕНИЯ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{principal_full_name}}, именуемый(-ая) в дальнейшем "Доверитель", с одной стороны, и {{agent_full_name}}, именуемый(-ая) в дальнейшем "Поверенный", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Доверитель поручает, а Поверенный принимает на себя обязательство совершить от имени и за счет Доверителя следующие юридические действия: {{legal_actions}}.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ВОЗНАГРАЖДЕНИЕ</div><p style="text-align: justify;">2.1. Размер вознаграждения составляет {{commission_amount}} рублей.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Доверитель:</strong><br/>{{principal_full_name}}<br/>Адрес: {{principal_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{principal_signature}}/</td><td width="50%" style="text-align: center;"><strong>Поверенный:</strong><br/>{{agent_full_name}}<br/>Адрес: {{agent_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{agent_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'principal_full_name', 'Наименование доверителя', 'agent_full_name', 'Наименование поверенного', 'legal_actions', 'Описание юридических действий', 'commission_amount', 'Размер вознаграждения', 'principal_address', 'Адрес доверителя', 'agent_address', 'Адрес поверенного', 'principal_signature', 'Подпись доверителя', 'agent_signature', 'Подпись поверенного')),

-- НЕДВИЖИМОСТЬ
('Договор мены недвижимости', 'real_estate', 'Договор мены недвижимого имущества', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">ДОГОВОР МЕНЫ НЕДВИЖИМОГО ИМУЩЕСТВА № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{party1_name}}, именуемый(-ая) в дальнейшем "Первая сторона", с одной стороны, и {{party2_name}}, именуемый(-ая) в дальнейшем "Вторая сторона", с другой стороны, заключили настоящий договор о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ ДОГОВОРА</div><p style="text-align: justify;">1.1. Первая сторона передает Второй стороне в собственность недвижимое имущество: {{property1_description}} по адресу: {{property1_address}}.</p><p style="text-align: justify;">1.2. Вторая сторона передает Первой стороне в собственность недвижимое имущество: {{property2_description}} по адресу: {{property2_address}}.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Первая сторона:</strong><br/>{{party1_name}}<br/>Адрес: {{party1_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{party1_signature}}/</td><td width="50%" style="text-align: center;"><strong>Вторая сторона:</strong><br/>{{party2_name}}<br/>Адрес: {{party2_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{party2_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'party1_name', 'Наименование первой стороны', 'party2_name', 'Наименование второй стороны', 'property1_description', 'Описание имущества первой стороны', 'property1_address', 'Адрес имущества первой стороны', 'property2_description', 'Описание имущества второй стороны', 'property2_address', 'Адрес имущества второй стороны', 'party1_address', 'Адрес первой стороны', 'party2_address', 'Адрес второй стороны', 'party1_signature', 'Подпись первой стороны', 'party2_signature', 'Подпись второй стороны')),

-- СЕМЕЙНЫЕ ДОГОВОРЫ
('Соглашение об уплате алиментов', 'family', 'Соглашение об уплате алиментов на ребенка', '<div style="text-align: center; font-weight: bold; font-size: 16pt; margin-bottom: 30px;">СОГЛАШЕНИЕ ОБ УПЛАТЕ АЛИМЕНТОВ № {{contract_number}}</div><div style="text-align: right; margin-bottom: 20px;">г. {{city}}, {{contract_date}}</div><p style="text-align: justify; line-height: 1.6;">{{payer_name}}, именуемый(-ая) в дальнейшем "Плательщик алиментов", с одной стороны, и {{recipient_name}}, именуемый(-ая) в дальнейшем "Получатель алиментов", с другой стороны, заключили настоящее соглашение о нижеследующем:</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">1. ПРЕДМЕТ СОГЛАШЕНИЯ</div><p style="text-align: justify;">1.1. Плательщик алиментов обязуется уплачивать алименты на содержание {{child_name}} в размере {{alimony_amount}} рублей ежемесячно.</p><div style="text-align: center; font-weight: bold; margin: 20px 0;">2. ПОРЯДОК УПЛАТЫ</div><p style="text-align: justify;">2.1. Алименты перечисляются на банковский счет получателя не позднее {{payment_deadline}} числа каждого месяца.</p><table width="100%" style="margin-top: 30px;"><tr valign="top"><td width="50%" style="text-align: center;"><strong>Плательщик:</strong><br/>{{payer_name}}<br/>Адрес: {{payer_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{payer_signature}}/</td><td width="50%" style="text-align: center;"><strong>Получатель:</strong><br/>{{recipient_name}}<br/>Адрес: {{recipient_address}}<br/><div style="border-bottom: 1px solid black; width: 150px; margin: 20px auto;"></div>/{{recipient_signature}}/</td></tr></table>', JSON_OBJECT('contract_number', 'Номер договора', 'city', 'Город заключения', 'contract_date', 'Дата заключения', 'payer_name', 'ФИО плательщика', 'recipient_name', 'ФИО получателя', 'child_name', 'ФИО ребенка', 'alimony_amount', 'Размер алиментов', 'payment_deadline', 'Срок уплаты', 'payer_address', 'Адрес плательщика', 'recipient_address', 'Адрес получателя', 'payer_signature', 'Подпись плательщика', 'recipient_signature', 'Подпись получателя')),

